const threshold = parseFloat($env.OKR_AT_RISK_THRESHOLD || 0.5);
const items = $input.all().map(i => {
  const d = i.json;
  const target = parseFloat(d.target || 1);
  const current = parseFloat(d.current || 0);
  const progress = target > 0 ? current / target : 0;
  const status = progress >= 1 ? 'achieved' : progress >= threshold ? 'on_track' : 'at_risk';
  return { ...d, progress_pct: Math.round(progress * 100), status, progress_ratio: Math.round(progress * 100) / 100 };
});
const byObjective = {};
for (const item of items) {
  if (!byObjective[item.objective]) byObjective[item.objective] = { objective: item.objective, key_results: [], avg_progress: 0, status: 'on_track' };
  byObjective[item.objective].key_results.push(item);
}
for (const obj of Object.values(byObjective)) {
  obj.avg_progress = Math.round(obj.key_results.reduce((s,kr) => s + kr.progress_pct, 0) / obj.key_results.length);
  obj.status = obj.key_results.some(kr => kr.status === 'at_risk') ? 'at_risk' : obj.key_results.every(kr => kr.status === 'achieved') ? 'achieved' : 'on_track';
}
const objectives = Object.values(byObjective);
return [{ json: { week: new Date().toISOString().slice(0,10), total_krs: items.length, at_risk: items.filter(i => i.status === 'at_risk').length, on_track: items.filter(i => i.status === 'on_track').length, achieved: items.filter(i => i.status === 'achieved').length, objectives } }];

